/**
 * Icon Helper Functions
 *
 * Renders Heroicons SVG inline. UI icons use stroke style (outline).
 * Brand/social icons use fill style and a separate wrapper.
 *
 * Usage:
 *   echo jalaversity_icon( 'phone' );
 *   echo jalaversity_icon( 'arrow-right', 18, 'my-class' );
 *   jalaversity_icon_e( 'search', 20 );
 *
 * @package Jalaversity
 */

if ( ! defined( 'ABSPATH' ) ) {
	exit;
}

