/**
 * Return SVG HTML for a UI icon (stroke/outline style).
 *
 * @param string $name  Icon name from jalaversity_icon_paths().
 * @param int    $size  Width and height in pixels (default 24).
 * @param string $class Optional CSS class(es) added to <svg>.
 * @return string       Safe SVG HTML.
 */
function jalaversity_icon( string $name, int $size = 24, string $class = '' ): string {
	$paths = jalaversity_icon_paths();

	if ( ! isset( $paths[ $name ] ) ) {
		return '';
	}

	$cls_attr = $class ? ' class="' . esc_attr( $class ) . '"' : '';

	return sprintf(
		'<svg xmlns="http://www.w3.org/2000/svg" width="%1$d" height="%1$d" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.75" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"%2$s>%3$s</svg>',
		absint( $size ),
		$cls_attr,
		$paths[ $name ]
	);
}

/**
 * Echo SVG HTML for a UI icon.
 *
 * @param string $name  Icon name.
 * @param int    $size  Size in pixels.
 * @param string $class Optional CSS class.
 */
function jalaversity_icon_e( string $name, int $size = 24, string $class = '' ): void {
	// phpcs:ignore WordPress.Security.EscapeOutput.OutputNotEscaped
	echo jalaversity_icon( $name, $size, $class );
}
